SELECT 
FROM employees


        AND (employee_number LIKE CONCAT('%', #{keyword}, '%')
            OR first_name LIKE CONCAT('%', #{keyword}, '%')
            OR last_name LIKE CONCAT('%', #{keyword}, '%')
            OR full_name LIKE CONCAT('%', #{keyword}, '%')
            OR english_name LIKE CONCAT('%', #{keyword}, '%')
            OR company_email LIKE CONCAT('%', #{keyword}, '%'))


        AND department_id = #{departmentId}


        AND employment_status = #{employmentStatus}


        AND employment_type = #{employmentType}


        AND hire_date >= #{hireDateFrom}


        AND hire_date <= #{hireDateTo}


ORDER BY employee_number
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM employees


        AND (employee_number LIKE CONCAT('%', #{keyword}, '%')
            OR first_name LIKE CONCAT('%', #{keyword}, '%')
            OR last_name LIKE CONCAT('%', #{keyword}, '%')
            OR full_name LIKE CONCAT('%', #{keyword}, '%')
            OR english_name LIKE CONCAT('%', #{keyword}, '%')
            OR company_email LIKE CONCAT('%', #{keyword}, '%'))


        AND department_id = #{departmentId}


        AND employment_status = #{employmentStatus}


        AND employment_type = #{employmentType}


        AND hire_date >= #{hireDateFrom}


        AND hire_date <= #{hireDateTo}

SELECT COUNT(*) FROM employees e
JOIN departments d ON e.department_id = d.department_id
WHERE d.organization_id = #{organizationId}
